#include <bits/stdc++.h>
using namespace std;

int n;
long long f[9][9][9][9][15],s[9][9];
bool to[9][9][9][9];

long long cal(int xl,int yl,int xr,int yr){
    return pow(s[xr][yr]-s[xl-1][yr]-s[xr][yl-1]+s[xl-1][yl-1],2);//统计矩形总分的平方
}

void dfs(int xl,int yl,int xr,int yr){
    if(to[xl][yl][xr][yr])
        return;//已经被遍历计算过的矩形直接退出
    to[xl][yl][xr][yr]=1;//标记已被遍历
    for(int i=1;i<15;i++)
        f[xl][yl][xr][yr][i]=1e18;//初始化为无穷大，避免被不合法方案转移
    f[xl][yl][xr][yr][1]=cal(xl,yl,xr,yr);
    for(int i=2;i<=xr-xl+yr-yl;i++){//一个矩形最多被切xr-xl+yr-yl次
        for(int j=xl;j<xr;j++){//枚举横着切的地方
            dfs(xl,yl,j,yr);
            dfs(j+1,yl,xr,yr);
            //搜索
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][yl][j][yr][i-1]+cal(j+1,yl,xr,yr));
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[j+1][yl][xr][yr][i-1]+cal(xl,yl,j,yr));
            //转移
        }
        for(int j=yl;j<yr;j++){//枚举竖着切的地方
            dfs(xl,yl,xr,j);
            dfs(xl,j+1,xr,yr);
            //搜索
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][yl][xr][j][i-1]+cal(xl,j+1,xr,yr));
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][j+1][xr][yr][i-1]+cal(xl,yl,xr,j));
            //转移
        }
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=8;i++)
        for(int j=1;j<=8;j++){
            scanf("%d",&s[i][j]);
            s[i][j]+=s[i-1][j]+s[i][j-1]-s[i-1][j-1];
            //统计前缀和
        }
    dfs(1,1,8,8);//记忆化搜索
    printf("%.3lf",sqrt(1.0*f[1][1][8][8][n]/n-pow(1.0*s[8][8]/n,2)));//直接套公式
    return 0;
}
